fn quicksort<T: Ord + Copy>(arr: &mut [T]) {
    let len = arr.len();
    if len <= 1 { return; }
    let pivot = arr[len / 2];
    let mut left = 0;
    let mut right = len - 1;
    while left < right {
        while arr[left] < pivot { left += 1; }
        while arr[right] > pivot { right -= 1; }
        if left < right {
            arr.swap(left, right);
            left += 1;
            right -= 1;
        }
    }
    quicksort(&mut arr[..left]);
    quicksort(&mut arr[left..]);
}

struct IteratorChain<I: Iterator> {
    inner: I,
}

impl<I: Iterator> IteratorChain<I> {
    fn new(iter: I) -> Self {
        IteratorChain { inner: iter }
    }
}

impl<I: Iterator> Iterator for IteratorChain<I> {
    type Item = I::Item;
    fn next(&mut self) -> Option<Self::Item> {
        self.inner.next()
    }
}

fn fibonacci(n: u32) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let (mut a, mut b) = (0u64, 1u64);
            for _ in 2..=n {
                let temp = a + b;
                a = b;
                b = temp;
            }
            b
        }
    }
}

enum Option<T> {
    Some(T),
    None,
}

impl<T> Option<T> {
    fn map<U, F: FnOnce(T) -> U>(self, f: F) -> Option<U> {
        match self {
            Option::Some(val) => Option::Some(f(val)),
            Option::None => Option::None,
        }
    }

    fn unwrap_or(self, default: T) -> T {
        match self {
            Option::Some(val) => val,
            Option::None => default,
        }
    }
}

fn binary_search(arr: &[i32], target: i32) -> Option<usize> {
    let mut left = 0;
    let mut right = arr.len();
    while left < right {
        let mid = left + (right - left) / 2;
        if arr[mid] == target {
            return Some(mid);
        } else if arr[mid] < target {
            left = mid + 1;
        } else {
            right = mid;
        }
    }
    None
}

