fn merge_sort<T: Ord + Clone>(arr: &[T]) -> Vec<T> {
    if arr.len() <= 1 {
        return arr.to_vec();
    }
    let mid = arr.len() / 2;
    let left = merge_sort(&arr[..mid]);
    let right = merge_sort(&arr[mid..]);
    merge(&left, &right)
}

fn merge<T: Ord + Clone>(left: &[T], right: &[T]) -> Vec<T> {
    let mut result = Vec::with_capacity(left.len() + right.len());
    let (mut i, mut j) = (0, 0);
    while i < left.len() && j < right.len() {
        if left[i] <= right[j] {
            result.push(left[i].clone());
            i += 1;
        } else {
            result.push(right[j].clone());
            j += 1;
        }
    }
    result.extend_from_slice(&left[i..]);
    result.extend_from_slice(&right[j..]);
    result
}

#[derive(Debug)]
enum Tree<T> {
    Empty,
    Node(Box<Tree<T>>, T, Box<Tree<T>>),
}

impl<T: Ord> Tree<T> {
    fn insert(&mut self, value: T) {
        *self = match self {
            Tree::Empty => Tree::Node(Box::new(Tree::Empty), value, Box::new(Tree::Empty)),
            Tree::Node(left, v, right) => {
                if value < *v {
                    left.insert(value);
                } else {
                    right.insert(value);
                }
                Tree::Node(Box::new(*left.clone()), *v, Box::new(*right.clone()))
            }
        };
    }
}

fn memoize<F, A, B>(mut f: F) -> impl FnMut(A) -> B
where
    F: FnMut(A) -> B + 'static,
    A: std::hash::Hash + Eq + Clone + 'static,
    B: Clone + 'static,
{
    use std::collections::HashMap;
    let mut cache = HashMap::new();
    move |arg: A| {
        cache.entry(arg.clone())
            .or_insert_with(|| f(arg))
            .clone()
    }
}

struct RetryError<E> {
    attempts: usize,
    last_error: E,
}

fn retry<F, T, E>(mut f: F, max_attempts: usize) -> Result<T, RetryError<E>>
where
    F: FnMut() -> Result<T, E>,
{
    let mut last_error = None;
    for attempt in 0..max_attempts {
        match f() {
            Ok(result) => return Ok(result),
            Err(e) => last_error = Some(e),
        }
    }
    Err(RetryError {
        attempts: max_attempts,
        last_error: last_error.unwrap(),
    })
}

fn flatten<T: Clone>(nested: &[Vec<T>]) -> Vec<T> {
    nested.iter()
        .flat_map(|inner| inner.iter().cloned())
        .collect()
}

trait Drawable {
    fn draw(&self);
    fn area(&self) -> f64;
}

struct Circle { radius: f64 }
struct Rectangle { width: f64, height: f64 }

impl Drawable for Circle {
    fn draw(&self) {
        println!("Drawing circle with radius {}", self.radius);
    }
    fn area(&self) -> f64 {
        std::f64::consts::PI * self.radius * self.radius
    }
}

impl Drawable for Rectangle {
    fn draw(&self) {
        println!("Drawing rectangle {}x{}", self.width, self.height);
    }
    fn area(&self) -> f64 {
        self.width * self.height
    }
}

fn group_by<T, K, F>(iter: impl Iterator<Item = T>, key_fn: F) -> std::collections::HashMap<K, Vec<T>>
where
    K: std::hash::Hash + Eq,
    F: Fn(&T) -> K,
{
    let mut result = std::collections::HashMap::new();
    for item in iter {
        let key = key_fn(&item);
        result.entry(key).or_insert_with(Vec::new).push(item);
    }
    result
}

use std::time::{Duration, Instant};

fn debounce<F, A>(mut f: F, delay: Duration) -> impl FnMut(A)
where
    F: FnMut(A) + 'static,
    A: 'static,
{
    let mut last_call: Option<Instant> = None;
    move |arg: A| {
        let now = Instant::now();
        if let Some(last) = last_call {
            if now.duration_since(last) < delay {
                return;
            }
        }
        last_call = Some(now);
        f(arg);
    }
}
